"""Juicy manual translations 101-200."""

T = {
101: {"nativeDefinition": "To become deeply absorbed in something, often spending excessive time on it.", "japaneseMeaning": "（何かに）のめり込む、深くハマる", "etymology": "『不思議の国のアリス』のウサギの穴から、次々と関連情報に引き込まれる比喩。", "examples": {"B": "Netflixで面白いものを探してたら、なぜかスポンジ工場のドキュメンタリーにのめり込んじゃった。すごく夢中になれる。", "C": "寝る前にWikipediaのウサギの穴に落ちるの、僕だけ？それともみんな？", "D": "何かに時間をかけすぎることに夢中になる。"}},
102: {"nativeDefinition": "Uninspiring; mediocre; expressing indifference.", "japaneseMeaning": "まあまあ、どうでもいい、イマイチ", "etymology": "感嘆詞としてのmehが、特に感動も失望もない反応を表す。", "examples": {"B": "隣のカジノで1万ドル当てた人が、まあまあって感じだった。どうして飛び上がって喜ばないんだ？", "C": "最初はこの曲イマイチだったけど、聞けば聞くほど好きになってきた。", "D": "退屈な。"}},
103: {"nativeDefinition": "To have thorough knowledge and expertise in one's field.", "japaneseMeaning": "（分野に）詳しい、プロだ", "etymology": "stuff（中身・専門知識）をknow（知る）で、本当に詳しいかを問う表現。", "examples": {"B": "税理士がいつも「調べて折り返します」って言うんだ。本当に詳しいの？って思う。", "C": "マットはまだ新人だから、当然まだ詳しくないよ。慣れる時間をあげれば大丈夫。", "D": "自分の分野に専門知識を持つ。"}},
104: {"nativeDefinition": "To make small adjustments to improve something.", "japaneseMeaning": "（何かを）少し調整する、微修正する", "etymology": "tweak（少し曲げる・調整する）が細かい修正を表す。", "examples": {"B": "教授が言うには、レポートを完璧にするには言い回しを少し直せばいいだけだって。結局だいたい12時間かかった。", "C": "試合はギリギリまで争ったけど、また負けた。作戦を少し調整しないと。", "D": "何かを少し修正する。"}},
105: {"nativeDefinition": "Secret; kept confidential.", "japaneseMeaning": "内密の、秘密の", "etymology": "hush（静かに）を重ねた表現で、誰にも知られないようにすることを表す。", "examples": {"B": "なんで二人の関係を内密にしようとしてるの？会社の規則に反してるの？", "C": "来月異動させる予定なんだけど、まだ未定だから内密にしておいてくれる？", "D": "秘密の。"}},
106: {"nativeDefinition": "To evoke a strong feeling of understanding or connection in someone.", "japaneseMeaning": "（人の）心に響く、共感される", "etymology": "resonate（共鳴する）が、心の奥まで響くことを比喩的に表す。", "examples": {"B": "彼のTEDトークは本当に心に響いた。本当の幸せは他人ではなく自分の中から来るんだって気づいた。", "C": "僕のスピーチ、聴衆の心に響いたと思う？即興だったけど、自画自賛だけど結構よかったと思う。", "D": "誰かの心に響く。"}},
107: {"nativeDefinition": "Used when resuming a conversation after an interruption.", "japaneseMeaning": "どこまで話してたっけ", "etymology": "会話の途中で中断した地点を思い出す際の定型表現。", "examples": {"B": "どこまで話してたっけ？ああ、ストリートスマートとブックスマートは同じくらい大事だって話だったね。", "C": "どこまで話してたっけ？そうだ、週末に子どもたちが何してたか教えてくれてたところだ。", "D": "何を話す予定だった？"}},
108: {"nativeDefinition": "To increase something, such as a price or amount.", "japaneseMeaning": "（価格などを）上げる、引き上げる", "etymology": "bump up（突き上げる）が数値や水準を上げる意味。", "examples": {"B": "いつものカフェがコーヒーの値段を50セント上げた。悲しい一日だ。", "C": "GPAを最低3.0まで引き上げないと、留学プログラムに申し込めない。", "D": "何かを増やす。"}},
109: {"nativeDefinition": "Clear and sharp in sound or image; fresh and cool (of air).", "japaneseMeaning": "（音が）クリアな、（空気が）ひんやりした", "etymology": "crisp（パリッとした）が音の明瞭さや空気の清涼感を表す。", "examples": {"B": "このソニーのヘッドホン買ったんだけど、音がすごくクリアで低音も最高。間違いなくヘッドホンのゴールドスタンダードだ。", "C": "想像してみて、ひんやりした空気、いい匂い、清々しさ。冬が好きにならない理由が見つからない。", "D": "きれいで明瞭な。"}},
110: {"nativeDefinition": "To make the intended purpose or effort pointless.", "japaneseMeaning": "（目的を）台無しにする、意味がなくなる", "etymology": "defeat the purpose（目的を打ち負かす）で、やった意味がなくなることを表す。", "examples": {"B": "お客の立場に立つことはニーズを把握するプロセスだから、やった後に実践しなければ意味がない。", "C": "マスクを顎にかけてるの、明らかに意味ないでしょ？", "D": "何かを無意味にする。"}},
111: {"nativeDefinition": "To confuse or disorient someone.", "japaneseMeaning": "（人を）混乱させる、戸惑わせる", "etymology": "throw off（外す・乱す）が予想外のことで動揺させる意味。", "examples": {"B": "オーストラリア訛りは最初混乱したけど、今は一番わかりやすいと思う。", "C": "面接がすごく変だった。一番戸惑ったのは「このパンデミックをどう収束させますか？」って質問。答えがわかってたらここにいないよ。", "D": "人を混乱させる。"}},
112: {"nativeDefinition": "There is only a small difference between two things that are easily confused.", "japaneseMeaning": "紙一重の差がある", "etymology": "fine line（細い線）が、区別がほとんどない微妙な境界を表す。", "examples": {"B": "天才と狂気の間には紙一重の差がある。表裏一体みたいなものだ。", "C": "自信があることと、何でも知ってると思い込むことの間には紙一重の差がある。", "D": "二つのものの間にはわずかな違いがある。"}},
113: {"nativeDefinition": "Also known as; abbreviated as.", "japaneseMeaning": "別名、すなわち", "etymology": "also known as（〜としても知られる）の略がa.k.a.", "examples": {"B": "久保、別名日本のメッシが素晴らしいゴールを決めた。見事だった。", "C": "ここが僕の聖域、別名寝室。かっこいいでしょ？", "D": "別名。"}},
114: {"nativeDefinition": "In its current state; without changes.", "japaneseMeaning": "そのまま、現状のままで", "etymology": "as is（あるがままに）が変更なしの状態を表す。", "examples": {"B": "エッセイのこの部分を書き直そうかと思ったけど、そのままにすることにした。", "C": "なんでそんなに完璧主義なの？レポートはそのままで十分だよ。車輪の再発明はやめよう。", "D": "変更されていない。"}},
115: {"nativeDefinition": "To be unrealistic or daydreaming; not paying attention to reality.", "japaneseMeaning": "夢見がちな、現実を見てない", "etymology": "head in the clouds（頭が雲の中）が空想にふけっている状態を表す。", "examples": {"B": "エマとこの話をしたいんだけど、今は夢見がちみたいだから。また今度にしよう。", "C": "テリーの仕事はいつもセンスチェックする。いつも現実を見てないみたいだから。", "D": "非現実的な。"}},
116: {"nativeDefinition": "Good value for the money spent.", "japaneseMeaning": "コスパがいい、お金の価値がある", "etymology": "bang（打撃・インパクト）for the buck（ドル）で、投資に見合うリターンを表す。", "examples": {"B": "ホテルよりAirbnbを使った方がいいよ。コスパがずっといい。", "C": "どのMacBookが一番コスパいい？モデルが多すぎて選びにくい。", "D": "金銭的価値がある。"}},
117: {"nativeDefinition": "To trap someone in a difficult situation with no escape.", "japaneseMeaning": "（人を）追い詰める、窮地に陥らせる", "etymology": "corner（角）に追い込むイメージから、逃げ場のない状況を表す。", "examples": {"B": "母が今朝電話してきて、宿題終わるまで外で遊んじゃダメだって。", "C": "上司がいつも後ろから息をかけてくる。やめてほしい。追い詰められた感じになる。", "D": "逃げられない状況に誰かを追い込む。"}},
118: {"nativeDefinition": "To criticize or blame oneself excessively about something.", "japaneseMeaning": "（〜について）自分を責めすぎる", "etymology": "beat oneself up（自分を殴る）が過度の自責を比喩的に表す。", "examples": {"B": "大学中退のことで自分を責めてるけど、もう済んだことだ。", "C": "コントロールできないことで自分を責めるのはやめなきゃ。", "D": "自分自身や何かを批判する。"}},
119: {"nativeDefinition": "Before one was born or before one started a job or lived in a place.", "japaneseMeaning": "（自分が）知らない時代の、以前の", "etymology": "before one's time（自分の時代の前）が経験していない過去を指す。", "examples": {"B": "この曲は自分が知らない時代のものだけど、すごくいい。好きだ。", "C": "ここに来る前に同じ名前の人がいたって聞いたけど、本当？", "D": "誰かが生まれる前、働き始める前、住み始める前。"}},
120: {"nativeDefinition": "A large amount of money.", "japaneseMeaning": "大金、たくさんのお金", "etymology": "big（大きい）＋bucks（ドル・お金）で多額の金銭を表す。", "examples": {"B": "一歩引いて、なんで他人のために大金を稼ぐために必死になって、自分はピーナッツしかもらってないのか真剣に考えた方がいい。", "C": "彼は今大金を稼いでるのはわかるけど、彼に全部払わせるのはフェアじゃない。割り勘しよう。", "D": "たくさんのお金。"}},
121: {"nativeDefinition": "A famous or well-known person, company, or organization.", "japaneseMeaning": "大手、有名企業・有名人", "etymology": "big name（大きな名前）が業界で知られた存在を表す。", "examples": {"B": "記憶を呼び覚ましてくれる？F1の大手だと思うんだけど、誰だか思い出せない。", "C": "このプロジェクトにどれだけ大手が関わってるか見て。KPMG、デロイト、アクセンチュアなどなど。絶対大成功だ。", "D": "有名な会社や組織。"}},
122: {"nativeDefinition": "Through people telling each other, rather than advertising.", "japaneseMeaning": "口コミで、人づてに", "etymology": "word of mouth（口から口へ）が口コミによる広がりを表す。", "examples": {"B": "このバーは口コミで知った。地元の人しか知らない隠れた名店だ。", "C": "これ自体すごくいい商品だから、口コミで自然に広がると思う。", "D": "人々がそれについて話しているから。"}},
123: {"nativeDefinition": "In defense of someone; speaking in their support.", "japaneseMeaning": "（人の）弁護をすると、言い訳すると", "etymology": "in one's defense（誰かの防御として）が擁護の意味。", "examples": {"B": "靴を傷つけてごめん。でも言い訳すると、仕事で高いもの履かない方がいいよ。", "C": "シャノンが昨日怒鳴ったって聞いたけど、彼女らしくない。何かあったのかも。", "D": "誰かを支持する。"}},
124: {"nativeDefinition": "To fit something or someone into a busy schedule.", "japaneseMeaning": "（予定に）ねじ込む、時間を作る", "etymology": "squeeze in（押し込む）が忙しい中に時間を確保する意味。", "examples": {"B": "歯が痛くて死にそうなのに、歯医者は来週まで時間を作ってくれない。耐えるしかない。", "C": "毎朝仕事前にワークアウトをねじ込もうとしてるけど、計画通りにいかないこともある。", "D": "何かのために時間を作る。"}},
125: {"nativeDefinition": "Said when a problem is easily solved.", "japaneseMeaning": "問題解決、これで解決", "etymology": "problem solved（問題は解決した）が手っ取り早い解決を表す。", "examples": {"B": "交通事故が怖いなら、車を運転しなければいい。問題解決。", "C": "やばい、またテスト0点。母に見せたら殺されるから、とりあえず隠す。問題解決。", "D": "問題は解決した。"}},
126: {"nativeDefinition": "Welcoming and including everyone; or making efforts to include others.", "japaneseMeaning": "包括的な、みんなを受け入れる", "etymology": "include（含める）から、誰も排除しない姿勢を表す。", "examples": {"B": "同僚がもっと包括的になろうとしてるけど、僕は内気だと思われてるだけ。大人数で遊ぶのが好きじゃないだけなんだ。", "C": "友達はみんなかなり包括的だから、心配しないで。", "D": "積極的に友好的な。"}},
127: {"nativeDefinition": "A public acknowledgment or credit given to someone.", "japaneseMeaning": "シャウトアウト、紹介・称賛", "etymology": "shout out（叫びかける）が公の場での紹介・感謝を表す。", "examples": {"B": "この本に関わってくれたみんなに大きなシャウトアウトを。", "C": "彼女の好きな俳優が昨夜YouTubeライブで彼女にシャウトアウトして、めちゃくちゃ喜んでた。", "D": "クレジットの言及。"}},
128: {"nativeDefinition": "Natural human behavior or tendencies.", "japaneseMeaning": "人間の本性、人間らしさ", "etymology": "human（人間）＋nature（本性）で、人として当然の性質を表す。", "examples": {"B": "気にしないで。物を忘れるのは人間の本性だよ。ちょっと復習させて。", "C": "人間の本性は根本的に善なのか悪なのか、どう思う？", "D": "生来の人間の行動。"}},
129: {"nativeDefinition": "Characteristic or distinctive of a brand or person.", "japaneseMeaning": "（ブランドの）代名詞的な、看板の", "etymology": "signature（署名）がブランドを代表する特徴を表す。", "examples": {"B": "ルイ・ヴィトンの代名詞的なモノグラム、実はルイ・ヴィトンの息子がデザインしたの知ってた？", "C": "このトラベルヌードルを注文する。看板メニューなんだ。", "D": "最もよく知られている。"}},
130: {"nativeDefinition": "To join a conversation, often briefly.", "japaneseMeaning": "（会話に）口を挟む、ちょっと加わる", "etymology": "chime in（鐘が鳴る）が会話に割り込む意味。", "examples": {"B": "何の話してたかもわからないのに、口を挟めないよ。", "C": "言いたいこと全部は覚えてないから、会議中に抜けてたら口を挟んで。", "D": "会話に割り込む。"}},
131: {"nativeDefinition": "Excitement and publicity surrounding something.", "japaneseMeaning": "話題性、盛り上がり、ハイプ", "etymology": "hype（誇大宣伝）が過剰な期待や注目を表す。", "examples": {"B": "この映画は過大評価だと思う。なんでこんなに話題になってるのかわからない。", "C": "このバーに行きたいんだけど、話題性が高すぎる。落ち着いてから行こう。", "D": "興奮と注目。"}},
132: {"nativeDefinition": "To raise the level of quality or expectations.", "japaneseMeaning": "（基準・水準を）引き上げる", "etymology": "raise the standard（基準を上げる）が品質水準の向上を表す。", "examples": {"B": "新マネージャーがこのクラブの水準を引き上げて、全選手のベストを引き出してる。", "C": "義務教育にオンライン英会話を取り入れたら、この国の英語水準は確実に上がる。", "D": "全体的な品質レベルを上げる。"}},
133: {"nativeDefinition": "At most; no more than.", "japaneseMeaning": "せいぜい、最大でも", "etymology": "tops（頂点）が上限を示す口語表現。", "examples": {"B": "Tシャツに200ドル？高すぎ。すぐ着古すからせいぜい50ドルまで。", "C": "iPhone 6のバッテリーがダメになってきた。せいぜい2時間持つ。MacBookもそろそろダメかも。", "D": "最大で。"}},
134: {"nativeDefinition": "Used to command attention before speaking.", "japaneseMeaning": "ちょっと聞いて、注目して", "etymology": "listen up（聞き上げる）が注意を促す命令形。", "examples": {"B": "ちょっと聞いてくれる？外に出てボールを蹴りたいのはわかるけど、先に安全について話さなきゃ。", "C": "ここ聞いて。初心者向けのコースだから、中級以上の生徒は受講しちゃダメだよ、いい？", "D": "注意を払う。"}},
135: {"nativeDefinition": "Difficult to understand someone's thoughts or intentions.", "japaneseMeaning": "読みにくい、わかりにくい", "etymology": "hard to read（読みにくい）が人の本心が見えないことを表す。", "examples": {"B": "彼女は読みにくい。毎日メッセージくれるのに、デートに誘うと断られる。", "C": "上司は読みにくいから、いつも気が抜けない。", "D": "理解しにくい。"}},
136: {"nativeDefinition": "Willing to consider new ideas and different opinions.", "japaneseMeaning": "オープンマインドな、偏見のない", "etymology": "open-minded（心が開いている）が柔軟な思考を表す。", "examples": {"B": "カイリーはオープンマインドな人だと思う？お腹に巨大なミッキーマウスのタトゥーを入れようとしても何も言わなかったから、たぶんそうだね。", "C": "彼が成功してるのは本当にオープンマインドだから。いろんな意見をちゃんと聞く。", "D": "偏見がなく新しい考えに受け入れやすい。"}},
137: {"nativeDefinition": "To deliberately ignore or shut out something unpleasant.", "japaneseMeaning": "（不快なことを）意識から追い出す、無視する", "etymology": "block out（遮る）が心から追い払うことを表す。", "examples": {"B": "インフルエンサーとして生計を立てたいなら、ネガティブなコメントを意識から追い出すのが上手くならないと。", "C": "絵文字使いすぎると年齢がバレるけど、やめられない。", "D": "何かを無視する。"}},
138: {"nativeDefinition": "To reveal someone's age through their behavior or preferences.", "japaneseMeaning": "（人の）年齢がわかる、年を感じさせる", "etymology": "show one's age（年齢を見せる）が世代がわかる行動を表す。", "examples": {"B": "絵文字使いすぎると年齢がバレるのはわかってるけど、やめられない。", "C": "インスタに何でも投稿するから、僕の人生はオープンブックだ。", "D": "誰かの年齢がわかる。"}},
139: {"nativeDefinition": "Someone who becomes upset or angry when they lose.", "japaneseMeaning": "負けず嫌い、負けて怒る人", "etymology": "sore（痛い・むくれた）＋loser（負け犬）で負けへの過剰反応を表す。", "examples": {"B": "負けそうになると毎回ログアウトする。本当に負けず嫌いだ。", "C": "負けて怒るタイプだね。ゲームだよ。", "D": "負けると動揺する人。"}},
140: {"nativeDefinition": "Go ahead; used to invite someone to ask questions or speak.", "japaneseMeaning": "どうぞ、遠慮なく", "etymology": "fire away（撃ち始めろ）が質問や発言を促す表現。", "examples": {"B": "質問ある？ノート取るからちょっと待って。よし、どうぞ。", "C": "どうぞ、何でも聞いて。", "D": "どうぞ。"}},
141: {"nativeDefinition": "To become addicted to or obsessed with something.", "japaneseMeaning": "（〜に）ハマる、夢中になる", "etymology": "hooked（釣り針にかかった）が中毒的な没頭を表す。", "examples": {"B": "ここ数週間この漫画にハマってる。ひどいくらい面白い。", "C": "いつからロック音楽好きになったの？僕の影響でハマった？", "D": "何かに夢中になる。"}},
142: {"nativeDefinition": "Intentional; part of a deliberate plan.", "japaneseMeaning": "計画の一部、意図的な", "etymology": "part of the plan（計画の一部）が意図された行動を表す。", "examples": {"B": "Googleマップが間違った道を示してるけど、これも計画の一部なのかな。", "C": "それは計画通りだよ。心配しないで。", "D": "意図的な。"}},
143: {"nativeDefinition": "To cancel a planned event or activity.", "japaneseMeaning": "（イベントなどを）中止する", "etymology": "call off（呼び止める）が予定を取りやめる意味。", "examples": {"B": "出席者が少なそうだから、今日のワークショップが中止にならないか心配。", "C": "雨の予報だから、ピクニックは中止にしよう。", "D": "何かをキャンセルする。"}},
144: {"nativeDefinition": "I'm ready whenever you are.", "japaneseMeaning": "準備できたら言って、いつでもいいよ", "etymology": "ready when you are（あなたが準備できたら）が相手のタイミングに合わせる表現。", "examples": {"B": "電話してほしいタイミングで教えて。いつでも準備できてる。", "C": "準備できたら始めよう。僕はいつでもいいよ。", "D": "今すぐ準備できてる。"}},
145: {"nativeDefinition": "Okay; all right (informal, cheerful).", "japaneseMeaning": "オッケー、了解", "etymology": "okey-dokeyはOKの親しみやすい言い換え。", "examples": {"B": "面白い話があるの？オッケー、オッケー、聞いてるよ。", "C": "オッケー、じゃあそうしよう。", "D": "了解。"}},
146: {"nativeDefinition": "For some unknown reason.", "japaneseMeaning": "なぜか、理由はわからないけど", "etymology": "for whatever reason（どんな理由であれ）が原因不明を表す。", "examples": {"B": "トーマスは来週ニュージーランドに旅行する予定だったけど、なぜかキャンセルした。", "C": "なぜか彼女は突然会社を辞めた。", "D": "説明なく。"}},
147: {"nativeDefinition": "I thought or assumed (something).", "japaneseMeaning": "〜だと思った、察していた", "etymology": "I figured（推測した）が「そうだろうと思った」という意味。", "examples": {"B": "メッセージ無視してごめんって言わなくていいよ。忙しいんだろうと思ってた。", "C": "遅刻するんだろうと思ってた。やっぱりね。", "D": "そう思った。"}},
148: {"nativeDefinition": "Very popular and fashionable at the moment.", "japaneseMeaning": "大流行の、今すごく人気の", "etymology": "all the rage（大いに流行）が一時的な大ブームを表す。", "examples": {"B": "韓国ものが今大流行してる。なんでそんなに騒がれてるのかわからない。", "C": "このブランドのバッグが大流行してる。", "D": "とても人気でトレンディな。"}},
149: {"nativeDefinition": "Sensational headlines designed to attract clicks, often misleading.", "japaneseMeaning": "クリックベイト、釣りタイトル", "etymology": "click（クリック）＋bait（餌）で、釣り記事を表す。", "examples": {"B": "このニュースサイトにはもう行かない。クリックベイトの記事ばかりだ。", "C": "あの動画のタイトル、完全にクリックベイトだよ。", "D": "注目を集める欺瞞的なもの。"}},
150: {"nativeDefinition": "A silly or unintelligent person.", "japaneseMeaning": "おっちょこちょい、頭が空っぽな人", "etymology": "air（空気）＋head（頭）で、中身のない頭を比喩。", "examples": {"B": "議論のために言うけど、金持ちと頭がいい人、どっちを選ぶ？金持ちかな。", "C": "彼女はおっちょこちょいだけど、いい人だよ。", "D": "バカな人。"}},
151: {"nativeDefinition": "In a very remote, isolated area.", "japaneseMeaning": "どこにでもない田舎の、人里離れた", "etymology": "middle of nowhere（どこでもないど真ん中）が辺鄙な場所を表す。", "examples": {"B": "かなり人里離れたところに住んでるけど、ニューヨークのアパートよりずっと広くて幸せ。", "C": "酔っ払って気づいたら人里離れたところにいた。どうやって来たかわからない。テキーラはもう飲まない。", "D": "とても辺鄙な地域に。"}},
152: {"nativeDefinition": "Every day without change; continuously.", "japaneseMeaning": "毎日コツコツ、日々", "etymology": "day in, day out（日々）が変わらず続くことを表す。", "examples": {"B": "多くの賢い人は大器晩成型だ。この科学者は毎日コツコツ努力して、97歳でノーベル賞を取った。", "C": "毎日コツコツ働けば、早く退職できる。", "D": "絶えず。"}},
153: {"nativeDefinition": "A narrow escape from danger or disaster.", "japaneseMeaning": "危ないところだった、ギリギリセーフ", "etymology": "close call（近い呼び出し）が危機一髪の場面を表す。", "examples": {"B": "電車との間違いかけた。まだビクビクしてる。", "C": "ふう、危なかった。飛行機乗り遅れるところだった。", "D": "危険からの狭い脱出。"}},
154: {"nativeDefinition": "Excessive; more than necessary.", "japaneseMeaning": "やりすぎ、過剰", "etymology": "overkill（殺しすぎ）が必要以上のことを表す。", "examples": {"B": "バーガーは美味しかったけど、パティ4枚はやりすぎ。誰がこれ食べ終われるの？", "C": "彼女のメイクの量はやりすぎ。整形したみたいに見える。", "D": "過剰。"}},
155: {"nativeDefinition": "A minor problem or temporary setback.", "japaneseMeaning": "ちょっとした問題、つまずき", "etymology": "hiccup（しゃっくり）が小さな障害の比喩。", "examples": {"B": "フォロワー1000人まであと少し。今月末には達成できそう、ちょっとした問題がなければ。", "C": "もう遅れてるから、これ以上つまずきは許されない。マイクをプロジェクトに入れて安定させる。", "D": "小さな問題や挫折。"}},
156: {"nativeDefinition": "To be better than something else.", "japaneseMeaning": "（何かに）勝る、〜に勝る", "etymology": "beat（打ち負かす）が他より優れていることを表す。", "examples": {"B": "ヨーロッパ一人旅に戻ると、一人旅は誰かと一緒より絶対いい。自分のルートを選べるから。", "C": "エベレスト頂上は人生で一番きつかった。でもあの達成感に勝るものはない。", "D": "何かより優れている。"}},
157: {"nativeDefinition": "I regret my decision; what was I thinking?", "japaneseMeaning": "何考えてたんだろう、後悔してる", "etymology": "what was I thinking（何を考えていた）が自分の判断への後悔を表す。", "examples": {"B": "何考えてたんだろう。このスタートアップに投資するのは確実だと思って全額入れたけど、誰がこのアプリ欲しいの？", "C": "来週スカイダイビングに申し込んじゃった。何考えてたんだ。飛行機から飛び降りるなんてこれ以上バカなことない。", "D": "これをしたことを後悔する。"}},
158: {"nativeDefinition": "The advantages and disadvantages of something.", "japaneseMeaning": "長所と短所、メリット・デメリット", "etymology": "pros（賛成）and cons（反対）で両面の評価を表す。", "examples": {"B": "誰にも長所と短所がある。完璧なパートナーを探すのはやめよう。時間の無駄だ。", "C": "Amazonにも長所短所あるのはわかってるけど、それでもeコマースの先駆者だと思う。", "D": "長所と短所。"}},
159: {"nativeDefinition": "A day or period that is completely unproductive.", "japaneseMeaning": "ダメな一日、潰れた日", "etymology": "write-off（帳消し）が費やす価値のない時間を表す。", "examples": {"B": "今日は完全に潰れた。午前中ずっと会議で、午後はインターネットが止まった。もう帰ろう。", "C": "今夜トビーと飲むからショットもやるだろうし、明日は潰れるだろうね。", "D": "生産性のない時間。"}},
160: {"nativeDefinition": "A hidden drawback or trick in an apparently good deal.", "japaneseMeaning": "裏がある、罠", "etymology": "catch（引っかかり）が見かけより良い取引の落とし穴を表す。", "examples": {"B": "新品同様のMacが50ドル？良すぎて信じられない。どこかに罠があるはず。", "C": "誰かがすごく親切にしてくれたら、いつも裏があると思う。", "D": "トリック。"}},
161: {"nativeDefinition": "Something unfortunate that just happens; it can't be helped.", "japaneseMeaning": "そういうものだ、仕方ない", "etymology": "just one of those things（そういうことの一つ）が仕方ない出来事を表す。", "examples": {"B": "美容院で少しだけ上を切ってって言ったのに、また丸刈りにされた。そういうものかな。", "C": "クリーニング取りに行かなきゃ。面倒だけど、そういうものだ。", "D": "こういうことは起きる。"}},
162: {"nativeDefinition": "Unwilling to change one's habits or ways of doing things.", "japaneseMeaning": "古いやり方に固執している", "etymology": "stuck in one's ways（自分のやり方に固まる）が変化を拒むことを表す。", "examples": {"B": "多くの日本企業はまだ古いやり方に固執してる。例えば紙と印鑑をまだ使ってる。", "C": "父はかなり古いやり方に固執してる。Googleマップ使わず紙の地図。老いた犬に新しい芸は教えられないね。", "D": "習慣や考え方を変える気がない。"}},
163: {"nativeDefinition": "To be verified as true or consistent.", "japaneseMeaning": "（話が）辻褄が合う、確認できる", "etymology": "check out（調べる）が事実と一致することを表す。", "examples": {"B": "え、何？話が辻褄合わないよ。昨夜家で勉強してたのに今朝ひどい二日酔い？飲んでたの？勉強してたの？", "C": "前に言ってたこと、辻褄が合ってる。この地域では米が魚より高くなってる。寿司に米がほとんどない。変だね。", "D": "筋が通る。"}},
164: {"nativeDefinition": "A remark intended to criticize or mock someone.", "japaneseMeaning": "（人への）嫌味、皮肉", "etymology": "dig at（突く）が人を刺すような発言を表す。", "examples": {"B": "君への嫌味じゃなかったよ。そのジャケットは誰が着てもバカみたいに見える。", "C": "たまに嫌味を言う人がいるけど、全然気にしない。集中するためのホワイトノイズだ。", "D": "批判的な発言。"}},
165: {"nativeDefinition": "Not aware of or connected to current reality or ordinary people.", "japaneseMeaning": "世間知らずの、現実と乖離している", "etymology": "out of touch（触れ合っていない）が現実から離れていることを表す。", "examples": {"B": "コーヒー1杯10ドルが安いって？普通の人と現実が乖離してるよ。", "C": "政府は人々が本当に必要としてることと現実が乖離してるように見える。", "D": "最新の知識を持っていない。"}},
166: {"nativeDefinition": "Refusing to accept an unpleasant truth.", "japaneseMeaning": "現実を受け入れていない、否認している", "etymology": "in denial（否定の中）が現実を認めない状態を表す。", "examples": {"B": "まだそのバカみたいな髪型を現実を受け入れてないの？学校では目立つけど、どうしようもないから受け入れよう。", "C": "まだ仕事を失ったことを現実として受け入れてないの？何もしないで座ってるのは時間の無駄だよ。早く新しい仕事探しなよ。", "D": "現実を受け入れていない。"}},
167: {"nativeDefinition": "Imagined; not real.", "japaneseMeaning": "気のせい、想像の産物", "etymology": "all in one's head（全部頭の中）が実際には存在しないことを表す。", "examples": {"B": "マットがいじめてるって言ってるけど、根拠ある？気のせいだと思う。他の人にも厳しいし。", "C": "彼が肩にチップを乗せてるのは気のせい？それとも全部想像？", "D": "誰かの想像の中にある。"}},
168: {"nativeDefinition": "Having very little time available.", "japaneseMeaning": "時間がない、急いでいる", "etymology": "pressed for time（時間に押される）が時間的余裕がないことを表す。", "examples": {"B": "時間がなかったから最後の問題は適当に答えたら正解だった。ラッキー。", "C": "時間がなくても規則通りにやるべき。手を抜くのは選択肢じゃない。", "D": "急いでいる。"}},
169: {"nativeDefinition": "Unchanged; the same as always.", "japaneseMeaning": "いつも通りの、変わらない", "etymology": "same old（いつもの）が変わらない状態を表す。", "examples": {"B": "コールセンターで2年働いてるから、もう少し皮が厚くなったかと思ったけど、やっぱりいつも通りの繊細な人間だ。", "C": "就活始めて2週間だけど、毎回同じ質問に答えるのにもううんざり。", "D": "変わっていない。"}},
170: {"nativeDefinition": "To remain calm and composed, especially under pressure.", "japaneseMeaning": "冷静さを保つ、ぐっと堪える", "etymology": "keep it together（まとめて保つ）が感情を抑えることを表す。", "examples": {"B": "エブリンはすごい。プレッシャーがかかっても冷静さを保つ。最高のプロジェクトリーダー。", "C": "卒業式ですごく泣いた。冷静さを保とうとしたけど、無理だった。", "D": "冷静さを保つ。"}},
171: {"nativeDefinition": "To manage to survive or cope with minimal resources.", "japaneseMeaning": "なんとかやっていく、足りる程度に", "etymology": "get by（通り抜ける）が最低限なんとかする意味。", "examples": {"B": "日本語学習に万能な方法はない。アニメをたくさん見たら、日本でなんとかやっていける程度には話せるようになった。", "C": "数年前はなんとかやっていくだけだったけど、ビジネスが軌道に乗ってお金が入ってきて、自分の家が買えた。", "D": "生き延びることができる。"}},
172: {"nativeDefinition": "It's complicated; too long to explain briefly.", "japaneseMeaning": "話が長い、詳しくは長い話", "etymology": "a long story（長い話）が簡潔に説明できないことを表す。", "examples": {"B": "長い話だけど、要するに鍵と財布とスマホを全部一日でなくした。", "C": "長い話だけど、アーロンとはもう関わりたくない。", "D": "とても複雑だ。"}},
173: {"nativeDefinition": "To have mixed feelings of both liking and disliking something.", "japaneseMeaning": "愛憎関係がある、好き嫌いが混在する", "etymology": "love-hate relationship（愛憎関係）が相反する感情を表す。", "examples": {"B": "クロックスとは愛憎関係がある。すごく楽なのに、見た目がダサい。", "C": "ごめん、鹿のつもりだった。オートコレクトとは愛憎関係だ。", "D": "何かを好きでも嫌いでもある。"}},
174: {"nativeDefinition": "Extremely thin; having very little flesh.", "japaneseMeaning": "骨と皮だけ、やせこけている", "etymology": "skin and bones（皮と骨）が極端に痩せた状態を表す。", "examples": {"B": "犬が骨と皮だけだよ。ちゃんと餌やってる？", "C": "痩せる必要ないよ。もう骨と皮だけだ。", "D": "極端に痩せている。"}},
175: {"nativeDefinition": "Innovative; pioneering; revolutionary.", "japaneseMeaning": "画期的な、革新的な", "etymology": "groundbreaking（地面を破る）が新しい道を切り開くことを表す。", "examples": {"B": "この会社のことを画期的だと言うのは少し大げさ。同じことをする会社がたくさんある。", "C": "当時オリジナルのFF7をプレイしたとき、グラフィックは画期的で度肝を抜かれた。", "D": "革新的または先駆的な。"}},
176: {"nativeDefinition": "To have a natural talent or skill for something.", "japaneseMeaning": "（〜の）才能がある、コツを掴んでいる", "etymology": "knack（コツ）をhave（持つ）で天性の得意分野を表す。", "examples": {"B": "次のチームリーダーに名前を出すべきだと思う。人を指導する才能がある。", "C": "絵の才能は本当にないから、どうやってデザイナーになったのかわからない。", "D": "何かに対する生来の才能を持つ。"}},
177: {"nativeDefinition": "On the surface; apparently.", "japaneseMeaning": "一見すると、表面的には", "etymology": "on the face of it（その表面で）が外見上の判断を表す。", "examples": {"B": "一見すると彼は落ち目に見えるけど、ただ不調のシーズンかもしれない。", "C": "一見データは本物っぽいけど、深く調べると数字が合わない。", "D": "表面的に。"}},
178: {"nativeDefinition": "To some extent; partially.", "japaneseMeaning": "ある程度、部分的に", "etymology": "to a degree（程度まで）が完全ではない同意や理解を表す。", "examples": {"B": "ある程度は同意する。初デートで割り勘すべきじゃなかったかもだけど、うまくいかなかった理由はそれじゃないと思う。", "C": "税金の仕組みはある程度わかるけど、プロじゃない。質問があればジェニーに聞いて。彼女は公認会計士だ。", "D": "ある程度。"}},
179: {"nativeDefinition": "Relating to or supporting what someone just said.", "japaneseMeaning": "おっしゃる通り、ご指摘のとおり", "etymology": "to your point（あなたの指摘に）が相手の意見に沿うことを表す。", "examples": {"B": "あなたのビジネスが好きなのは、ご指摘のとおり、お金がなくても学べる機会を学生に与えてるから。", "C": "ご指摘のとおり、データの正確性は疑わしい。誰も正当性を検証してないから、もっと批判的に調べる必要がある。", "D": "あなたが言ったことと一致して。"}},
180: {"nativeDefinition": "The kind of person someone is romantically attracted to.", "japaneseMeaning": "（恋愛の）タイプ", "etymology": "one's type（自分のタイプ）が好みの相手像を表す。", "examples": {"B": "彼女はすごく美人だけど、僕のタイプじゃない。手間がかかりすぎる。", "C": "紹介しようか？完全にあなたのタイプじゃないかもしれないけど、すごくいい人だよ。", "D": "誰かが魅力的だと思う人の種類。"}},
181: {"nativeDefinition": "To deliberately ignore or treat someone in an unfriendly way.", "japaneseMeaning": "（人に）冷たく当たる、無視する", "etymology": "cold shoulder（冷たい肩）が冷淡な扱いを表す。", "examples": {"B": "ウェイターが冷たく当たった。常連だって知らなかったのかな。", "C": "最近子どもたちに冷たくされてる気がする。理由がわからない。聞いてみよう。", "D": "意図的に無視するか不親切にする。"}},
182: {"nativeDefinition": "To be unaware of current events or popular culture.", "japaneseMeaning": "世間知らずの、情報に疎い", "etymology": "live under a rock（岩の下に住む）が世の中の出来事を知らないことを表す。", "examples": {"B": "カニエ・ウェストが誰かわからないなんて、世間知らずじゃない？", "C": "全部鵜呑みにしないで。これフェイクニュースで、数週間前に否定されてる。岩の下に住んでるの？", "D": "時事に関する知識が限られている。"}},
183: {"nativeDefinition": "Relating to physical stores rather than online businesses.", "japaneseMeaning": "実店舗の、リアル店舗の", "etymology": "brick（レンガ）and mortar（モルタル）が物理的な建物の店舗を表す。", "examples": {"B": "オンライン売上は去年から66%増えて、実店舗と肩を並べるくらいになった。ついに転換点に来たかも。", "C": "高額商品の分割払いのために、実店舗では無利息の分割払いができる。", "D": "物理的な。"}},
184: {"nativeDefinition": "To contribute to or reinforce a stereotype or outcome.", "japaneseMeaning": "（偏見などに）拍車をかける、助長する", "etymology": "play into（〜に役をする）が望ましくない結果を強化することを表す。", "examples": {"B": "ニックとの動画が、アメリカ人はスポットライトを独占するのが好きっていうステレオタイプを助長してるんじゃないか心配。", "C": "みんなが僕は内気だと思うのに、見た目がかわいいことを利用してる。", "D": "何かを強化する。"}},
185: {"nativeDefinition": "Wait; hold on a moment.", "japaneseMeaning": "ちょっと待って、待って", "etymology": "hold up（持ち上げる・止める）が「待って」を表すスラング。", "examples": {"B": "ちょっと待って、そのアイデアもう一度説明してくれる？よくわからなかった。", "C": "ちょっと待って、ラップトップがバグってる。再起動して配信再開する。ごめん、再開したら連絡するね。", "D": "待って。"}},
186: {"nativeDefinition": "Not typical of someone's character to do something.", "japaneseMeaning": "（人の）性質じゃない、らしくない", "etymology": "not in one's nature（本性にない）が普段の性格と合わないことを表す。", "examples": {"B": "仕事のことで怒るのは僕の性質じゃないけど、昇進しなかったのは残念。後で上司に話すけど、今は仕事を続ける。", "C": "小さなことで騒がない。それは僕の性質じゃない。", "D": "誰かがするようなこと。"}},
187: {"nativeDefinition": "To work hard and diligently at something.", "japaneseMeaning": "（〜に）真剣に取り組む、努力する", "etymology": "apply oneself（自分を適用する）が全力で取り組むことを表す。", "examples": {"B": "彼は勉強に真剣に取り組み始めたけど、手遅れかも。大学入試まであと2ヶ月しかない。", "C": "人生で一番大事なのは、他人が望むことじゃなく、自分が好きなことに真剣に取り組むこと。", "D": "何かに一生懸命働く。"}},
188: {"nativeDefinition": "A proven method or formula for achieving success.", "japaneseMeaning": "成功の秘訣、成功のレシピ", "etymology": "recipe（レシピ）for success（成功）が成功の型を表す。", "examples": {"B": "ビジネスを書くことに関しては、成功の秘訣なんてないと思う。コツコツやるだけ。", "C": "このチームは成功のレシピを持ってる。多くの選手が欠場しても、いつも勝ち方を見つける。", "D": "成功するための方法。"}},
189: {"nativeDefinition": "A short time after something has started.", "japaneseMeaning": "（始まってから）数分後", "etymology": "a few minutes into（〜に入って数分）が開始直後を表す。", "examples": {"B": "この本、始めて数分で既に退屈。", "C": "主人公が死んだ？数分で？何だこれ？", "D": "何かが始まってから数分後。"}},
190: {"nativeDefinition": "To complete a task successfully.", "japaneseMeaning": "（仕事を）やり遂げる、任務を果たす", "etymology": "get the job done（仕事を終わらせる）が目的を達成することを表す。", "examples": {"B": "仕事はやり遂げるから、マイクロマネジメントしないで。", "C": "ヘレンはコーチングの時間をかければ、ちゃんとやり遂げる。", "D": "タスクを完了する。"}},
191: {"nativeDefinition": "An unknown or unimportant person.", "japaneseMeaning": "無名の人、誰でもない人", "etymology": "nobody（誰でもない人）が無名・取るに足らない人を表す。", "examples": {"B": "トロイが今テレビに出まくってるなんて信じられない。3週間前に会ったときは無名だった。", "C": "バーテンダーが僕たちを誰でもない扱いしたの知ってる？服装のせいかな。次はスーツで行こうか。", "D": "無名または取るに足らない人。"}},
192: {"nativeDefinition": "Not feeling completely well or healthy.", "japaneseMeaning": "体調が万全じゃない、元気がない", "etymology": "not a hundred percent（100％ではない）が完全な健康状態でないことを表す。", "examples": {"B": "体調が万全じゃないなら、数日休んだ方がいいかも。", "C": "ここ数日ずっと万全じゃないけど、明日には大丈夫なはず。木を叩いて。", "D": "体調が良くない。"}},
193: {"nativeDefinition": "To influence someone, often unconsciously, through one's behavior.", "japaneseMeaning": "（人に）影響を与える、染まる", "etymology": "rub off on（擦り付けて染み込む）が影響が伝わることを表す。", "examples": {"B": "このYouTuberの影響で、毎日勉強するようになった。最初は嫌だったけど、今は好き。新しいことを学ぶのは楽しい。", "C": "おい、僕の影響でロック音楽好きになったの？いつから？", "D": "誰かに影響を与える。"}},
194: {"nativeDefinition": "To consider carefully before acting.", "japaneseMeaning": "よく考える、二思案する", "etymology": "think twice（二度考える）が慎重に検討することを表す。", "examples": {"B": "SNSに他人の個人情報を投稿するのは卑怯だ。そんなことする前によく考えた方がいい。", "C": "このサイトから買う前によく考えて。すごく怪しく見える。", "D": "立ち止まって再考する。"}},
195: {"nativeDefinition": "I didn't know that; that's new information to me.", "japaneseMeaning": "初耳だ、知らなかった", "etymology": "that's news to me（それは僕にとってニュースだ）が初めて聞くことを表す。", "examples": {"B": "新しい彼氏いるの？初耳だ。元カレと別れたばかりなのに。", "C": "中国語話せるの？知らなかった。", "D": "知らなかった。"}},
196: {"nativeDefinition": "I promise to keep a secret.", "japaneseMeaning": "口外しない、秘密は守る", "etymology": "lips are sealed（唇は封じられている）が秘密を守る誓いを表す。", "examples": {"B": "心配しないで、今日一日仕事中Netflix見てたこと誰にも言わない。口は堅いよ。", "C": "何考えてるの？言ってよ。口外しないから。", "D": "秘密を誰にも言わないと約束する。"}},
197: {"nativeDefinition": "Something that seems bad but turns out to be beneficial.", "japaneseMeaning": "不幸中の幸い、思わぬ幸運", "etymology": "blessing in disguise（変装した祝福）が見かけ倒しの不幸が実は幸いであることを表す。", "examples": {"B": "好きな人にゴーストされたのはつらいけど、不幸中の幸いだと思う。もう時間を無駄にしなくていいし、前に進める。", "C": "サイズが売り切れで買えなかったのは不幸中の幸い。お金使わなくて済んだ。", "D": "実はポジティブなこと。"}},
198: {"nativeDefinition": "Expressing nostalgia for a happy past time.", "japaneseMeaning": "あの頃が良かった、懐かしいな", "etymology": "those were the days（あれがあの日々だった）が懐かしさを表す。", "examples": {"B": "マクドナルドのハンバーガーが60円だった頃を覚えてる？あの頃が良かった。", "C": "子どもの頃、父と一緒にドラゴンボールを見てた。あの頃が良かった。", "D": "あんなに素晴らしい時代だった。"}},
199: {"nativeDefinition": "Saying one's thoughts aloud without necessarily intending to.", "japaneseMeaning": "独り言、考えを声に出す", "etymology": "thinking out loud（声に出して考える）が独り言を表す。", "examples": {"B": "ねえ、動画が嫌いなら見なければいいんじゃない？わかんないけど、ただ独り言。", "C": "独り言だけど、香水のCMって嗅げないのに何の意味があるの？", "D": "考えを声に出すだけ。"}},
200: {"nativeDefinition": "At some point in the future.", "japaneseMeaning": "将来的に、いつか", "etymology": "down the track（線路の先）がオーストラリア英語で将来を表す。", "examples": {"B": "今は子どもは欲しくないけど、将来的には家族を持ちたい。", "C": "フルタイムの仕事を辞めてスタートアップに集中する決断をした。将来的に報われるといいな。", "D": "将来。"}},
}
